import { css } from '@linaria/core'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { HelpTip } from '@fs/zion-icon'
import { boolAttr } from '@fs/zion-frontend-friends'
import { Button, DialogOverlayActions, colors, useContainerWidth, H1, Subheading } from '@fs/zion-ui'
import { Overlay, DialogFooterWrapper } from '@fs/zion-ui/quarks-authorized-use-only'

const adCss = css`
  background-color: ${colors.gray00};
  position: fixed;
  bottom: 0;
  left: 0;
  max-width: 100%;
  z-index: 2;

  [non-mobile]& {
    bottom: 16px;
    left: 16px;
    max-width: 456px;
  }
`

const iconBlockCss = css`
  display: grid;
  grid-column-gap: 24px;
  grid-template-columns: auto 1fr;
  padding: 16px 20px 0;
`

const iconCss = css`
  background-color: ${colors.yellow30};
  border-radius: 50%;
  display: grid;
  height: 64px;
  margin-top: 8px;
  place-items: center;
  width: 64px;
`

export default function HelpAd({ overlayRef, title, description, declineHandler, startHandler }) {
  const { t } = useTranslation()
  const atWidth = useContainerWidth()
  return (
    <div className={adCss} non-mobile={boolAttr(atWidth({ sm: true }))}>
      <Overlay
        ref={overlayRef}
        aria-label={t('help-tutorial.tutorial-offer-dialog.overlay-aria', 'Overview Offer Dialog')}
      >
        {/* NOT USING <PersonBlock> because it does not accept Icons for the avatar */}
        <div className={iconBlockCss}>
          <div className={iconCss}>
            {/* HelpTip - Attempted to use shape="circle" but we also need padding a color options,
            so we opted to use a div and style it as needed */}
            <HelpTip color="#fff" size="md" />
          </div>
          <div>
            <H1 size="H5" supplementary>
              {title}
              <Subheading>{description}</Subheading>
            </H1>
          </div>
        </div>

        {/* Using DialogOverlay components here for consistent layout */}
        <DialogFooterWrapper>
          <DialogOverlayActions>
            <Button onClick={declineHandler}>{t('help-tutorial.no-thanks.button', 'No Thanks')}</Button>
            <Button emphasis="medium" onClick={startHandler}>
              {t('help-tutorial.start-tutorial.button', 'Start Overview')}
            </Button>
          </DialogOverlayActions>
        </DialogFooterWrapper>
      </Overlay>
    </div>
  )
}
